export function script(input) {
  const vulnerabilities = Array.isArray(input.vulnerabilities) ? input.vulnerabilities : [];
  const severityRank = { critical: 4, high: 3, medium: 2, low: 1, info: 0, unknown: 0 };
  const normalizeSeverity = (value) => String(value || 'unknown').toLowerCase();
  const rankFor = (value) => severityRank[normalizeSeverity(value)] ?? 0;
  const priorityFindings = vulnerabilities
    .map((finding) => ({
      vulnerabilityId: finding?.vulnerabilityId,
      pkgName: finding?.pkgName,
      severity: normalizeSeverity(finding?.severity),
      title: finding?.title,
      fixedVersion: finding?.fixedVersion || null
    }))
    .filter((finding) => finding.vulnerabilityId && rankFor(finding.severity) >= 2)
    .sort((a, b) => rankFor(b.severity) - rankFor(a.severity))
    .slice(0, 25);
  const countsBySeverity = priorityFindings.reduce((acc, finding) => {
    acc[finding.severity] = (acc[finding.severity] || 0) + 1;
    return acc;
  }, {});
  const highestSeverity = priorityFindings[0]?.severity || 'none';
  const imageRef = input.imageRef || 'unknown image';
  const summaryText = `${imageRef}: ${priorityFindings.length} actionable CVEs (highest: ${highestSeverity})`;
  const report = {
    summary: {
      imageRef,
      vulnerabilityCount: Number(input.vulnerabilityCount || vulnerabilities.length),
      actionableFindings: priorityFindings.length,
      highestSeverity,
      countsBySeverity
    },
    priorityFindings
  };
  return {
    summaryText,
    report,
    attachmentContent: JSON.stringify(report, null, 2)
  };
}
